import{_ as e,C as t,o as i,c as E,a2 as o,E as s}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Tool System 笔记：工具调用要有刹车","description":"","frontmatter":{},"headers":[],"relativePath":"agent/tool-system-notes.md","filePath":"agent/tool-system-notes.md","lastUpdated":1782239373000}'),A={name:"agent/tool-system-notes.md"};function r(n,l,p,c,d,B){const a=t("Mermaid");return i(),E("div",null,[l[0]||(l[0]=o('<h1 id="tool-system-笔记-工具调用要有刹车" tabindex="-1">Tool System 笔记：工具调用要有刹车 <a class="header-anchor" href="#tool-system-笔记-工具调用要有刹车" aria-label="Permalink to &quot;Tool System 笔记：工具调用要有刹车&quot;">​</a></h1><p>Agent 的能力来自工具，风险也来自工具。模型一旦能写文件、访问外部系统、执行代码、写记忆，就不只是“说错话”的问题了。</p><p>我现在对工具系统的理解很直接：模型输出的是意图，平台掌握的是执行权。</p><h2 id="从-function-calling-到工具治理" tabindex="-1">从 function calling 到工具治理 <a class="header-anchor" href="#从-function-calling-到工具治理" aria-label="Permalink to &quot;从 function calling 到工具治理&quot;">​</a></h2><p>最早的工具设计就是 function calling：定义工具名、描述、参数 schema，模型返回工具调用，后端执行。</p><p>这个版本很轻，但缺几个关键问题：</p><ul><li>当前用户是否有权限执行？</li><li>工具是否高风险？</li><li>是否需要用户审批？</li><li>一个 Turn 内最多能调用几次？</li><li>工具输出是否过长？</li><li>工具失败是否计入预算？</li><li>外部工具是否可信？</li><li>重试会不会重复产生副作用？</li></ul><p>这些问题说明，工具不应该只是函数列表，而应该是受治理资源。</p><h2 id="当前更稳的工具链路" tabindex="-1">当前更稳的工具链路 <a class="header-anchor" href="#当前更稳的工具链路" aria-label="Permalink to &quot;当前更稳的工具链路&quot;">​</a></h2>',9)),s(a,{code:"flowchart%20TD%0A%20%20%20%20Model%5B%22%E6%A8%A1%E5%9E%8B%E8%BE%93%E5%87%BA%E5%B7%A5%E5%85%B7%E6%84%8F%E5%9B%BE%22%5D%20--%3E%20Registry%5B%22Tool%20Registry%22%5D%0A%20%20%20%20Registry%20--%3E%20Allow%7B%22%E5%9C%A8%E5%85%81%E8%AE%B8%E5%88%97%E8%A1%A8%3F%22%7D%0A%20%20%20%20Allow%20--%20%22%E5%90%A6%22%20--%3E%20Reject%5B%22%E6%8B%92%E7%BB%9D%E6%89%A7%E8%A1%8C%22%5D%0A%20%20%20%20Allow%20--%20%22%E6%98%AF%22%20--%3E%20Risk%7B%22%E9%A3%8E%E9%99%A9%E7%AD%89%E7%BA%A7%20%2F%20%E5%AE%A1%E6%89%B9%E7%AD%96%E7%95%A5%22%7D%0A%20%20%20%20Risk%20--%20%22%E9%9C%80%E8%A6%81%E5%AE%A1%E6%89%B9%22%20--%3E%20Approval%5B%22%E7%AD%89%E5%BE%85%E7%94%A8%E6%88%B7%E7%A1%AE%E8%AE%A4%22%5D%0A%20%20%20%20Approval%20--%3E%20Registry%0A%20%20%20%20Risk%20--%20%22%E5%8F%AF%E6%89%A7%E8%A1%8C%22%20--%3E%20Executor%5B%22Tool%20Executor%22%5D%0A%20%20%20%20Executor%20--%3E%20Sandbox%7B%22%E9%9C%80%E8%A6%81%E6%B2%99%E7%AE%B1%3F%22%7D%0A%20%20%20%20Sandbox%20--%20%22%E6%98%AF%22%20--%3E%20Isolated%5B%22%E9%9A%94%E7%A6%BB%E8%BF%90%E8%A1%8C%22%5D%0A%20%20%20%20Sandbox%20--%20%22%E5%90%A6%22%20--%3E%20Direct%5B%22%E5%8F%97%E6%8E%A7%E6%89%A7%E8%A1%8C%22%5D%0A%20%20%20%20Isolated%20--%3E%20Result%5B%22%E7%BB%93%E6%9E%9C%E5%8C%85%E8%A3%85%22%5D%0A%20%20%20%20Direct%20--%3E%20Result%0A%20%20%20%20Result%20--%3E%20Observe%5B%22%E4%B8%8D%E5%8F%AF%E4%BF%A1%E8%A7%82%E5%AF%9F%E7%BB%93%E6%9E%9C%22%5D%0A"}),l[1]||(l[1]=o('<p>执行端必须重新检查权限。不能只靠“模型看不到这个工具”来保证安全。</p><p>工具输出也不能直接塞回模型。它可能包含用户文件、外部网页、错误堆栈、甚至恶意指令。回到上下文前要包装、截断、标记。</p><h2 id="tool-和-skill-的边界" tabindex="-1">Tool 和 Skill 的边界 <a class="header-anchor" href="#tool-和-skill-的边界" aria-label="Permalink to &quot;Tool 和 Skill 的边界&quot;">​</a></h2><p>Tool 负责行动，Skill 负责方法。</p><p>比如代码执行是 Tool，但“如何生成一个可靠的文档”“如何处理 PDF”“如何校验表格产物”更像 Skill。它们是操作规程，不应该长期塞在系统 Prompt 里，而应该在需要时加载。</p><p>Skill 如果没有版本、来源、触发和资产治理，也会变成供应链风险。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是只在模型可见列表里做权限。执行端不校验，就等于没有真正权限。</p><p>第二个坑，是工具风险不分层。读时间、写记忆、联网、执行代码、删除资源，这些风险完全不同。</p><p>第三个坑，是工具输出无限制。输出太长会撑爆上下文，输出不可信会污染下一轮推理。</p><p>第四个坑，是代码执行本地降级。模型生成的代码不可信，没有沙箱就不应该执行。</p><p>第五个坑，是外部工具接入太随意。工具来自哪里不重要，进入执行系统后必须经过同一套策略。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果重新做工具系统，我会把它当成 Agent 时代的 API 网关：</p><ul><li>schema 只是入口。</li><li>risk 和 policy 决定是否能执行。</li><li>quota 控制调用频率。</li><li>timeout 控制执行时间。</li><li>audit 记录副作用。</li><li>idempotency 降低重复执行风险。</li></ul><p>一句话总结：工具越强，边界越要硬；模型可以提议行动，但不能直接拥有执行权。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么 Tool 不是普通 function calling。</li><li>模型意图和平台执行权的区别。</li><li>Tool Registry 应该承担哪些职责。</li><li>Tool 和 Skill 为什么要分开。</li><li>外部工具为什么不能默认可信。</li><li>代码执行为什么必须进入沙箱。</li><li>如果重做，我会把工具系统做成 API 网关。</li></ol>',18))])}const m=e(A,[["render",r]]);export{h as __pageData,m as default};
